  ('social-worker-moex-00271', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關高齡者在記憶能力與學習的描述，在多數情況下，下列何者正確？', '["無論短期或長期記憶力能力都會衰退", "雖思考速度減緩，但仍具備一定的邏輯思考能力", "維持終身學習對其認知能力並無協助", "在成年晚期，個體的智力會有明顯的退化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00272', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「守恆（conservation）測驗」是常用在兒童中期認知層面發展狀況的心理測驗，根據Weiten（2003） 研究結果，一位6歲的兒童在那一種類型守恆測驗上的表現最佳？', '["體積守恆", "面積守恆", "長度守恆", "數量守恆"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00273', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據Cheek（1989）研究發現，當「個人以公我（publicself）為基礎，反映個人在社會中的角色 與關係，是個人與環境互動後形塑的認同樣貌」，這是那一部分的自我認同？', '["個人認同（personalidentity）", "家庭認同（familyidentity）", "社會認同（socialidentity）", "集體認同（collectiveidentity）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00274', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關優勢觀點的敘述，下列何者錯誤？', '["優勢觀點強調助人者是以專家的角色介入，指導家庭成員改變", "優勢觀點的一個重要信條是人類具有足夠的資源與彈性", "優勢觀點的假設是人們有成長、變化與適應能力", "優勢觀點認為家庭成員本身有能力解決家庭問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00275', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者對於服務對象的社會層面進行評估，下列何者不屬於社會層面的考量因素？', '["角色系統與次系統", "家庭溝通模式", "可運用的支持系統", "社交問題解決技巧"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00276', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Piaget 將道德發展分為無律／他律／自律等階段，當你問一個孩子為什麼不能玩火，對方回答媽 媽說不可以。試問孩子大概幾歲？', '["0～3歲", "4～8歲", "9～12歲", "20歲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00277', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '中年階段伴侶間的愛情與親密關係強調感性、分享、忠誠與穩健，此為Sternberg（1986）愛情三 角理論（triangulartheoryoflove）裡的那種愛情元素模式？', '["虛幻的愛（fatuouslove）", "伴侶的愛（companionatelove）", "空虛的愛（emptylove）", "浪漫的愛（romanticlove）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00278', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「孩童走路與跑步表現良好，能夠快速停下而不跌倒，開始將想像力運用在遊戲中，也喜歡模仿 大人的動作」。上列敘述符合幾歲的生理發展里程？', '["2歲", "3歲", "5歲", "6歲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00279', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Freud有關三歲幼兒的心理狀態發展，下列敘述何者錯誤？', '["開始模擬相同性別的家長，並以異性者為愛戀對象", "生活規範對三歲幼兒而言，是似有似無，似懂非懂的", "開始會送自己心愛的物件給家長作為生日禮物", "開始主動進行各種活動，若無法則會發展出內疚感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00280', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「就業」可說是成年人發展很重要的投入和參與，也對於個體的身體、心理和社會有重要影響， 下列敘述何者錯誤？', '["失業的人會覺得周遭的人不要他、自己不重要和缺乏社會角色", "沒有工作只會影響失業的個體", "長時間失業即使再找到工作仍會覺得自尊心低落", "沒有工作可能導致無家可歸的問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
